scwin.onpageload = function () {
  scwin.userId = $c.data.getMemInfo($p, "userId") || "";
  scwin.empNo = $c.data.getMemInfo($p, "userId") || "";
  scwin.vLobranCd = $c.data.getMemInfo($p, "lobranCd") || "";
  scwin.vLobranNm = $c.data.getMemInfo($p, "lobranNm") || "";
  scwin.p_kcomcd = $c.data.getParameter($p, "kcomcd") || scwin.hd_kcomcd;
  scwin.p_blno = $c.data.getParameter($p, "blno") || "";
  scwin.p_mblno = $c.data.getParameter($p, "mblno") || "";
  scwin.p_type = $c.data.getParameter($p, "type") || "";
  scwin.v_linkcheck = $c.data.getParameter($p, "linkcheck") || "";
  scwin.p_no = $c.data.getParameter($p, "no");
  scwin.p_row_cnt = $c.data.getParameter($p, "row_cnt");
  scwin.p_data = $c.data.getParameter($p, "data");
  scwin.p_hblno2 = $c.data.getParameter($p, "hblno");
  scwin.p_docuno = $c.data.getParameter($p, "docuno");
  scwin.strCurDate = $c.gus.cfGetCurrentDate($p) || "";
  var resData = $c.gus.dsCommonUtil($p, 'getCompanyInfoDTO', scwin.vLobranCd)[0].value.split('\n');
  var commDTO = resData.reduce((acc, curr) => {
    var match = curr.match(/^\s*\w+\s+(\w+)\s+=\s+\[(.*)\]/);
    if (match) {
      const key = match[1];
      let value = match[2];
      if (value == 'null') value = null;
      acc[key] = value;
    }
    ;
    return acc;
  }, {});
  scwin.p_clntNo = commDTO.clntNo;
  scwin.p_clntNm = commDTO.name1;
  scwin.airexgbim = commDTO.airExgbIm ? commDTO.airExgbIm : "4";
};
scwin.onUdcCompleted = async function () {
  scwin.f_OnLoad();
  scwin.initComp();
};
scwin.initComp = function () {
  //==============================================================================
  // UDC CommonCode Setting
  //==============================================================================
  var objCode = [ed_dpcd, ed_mftpacd, ed_sacd, ed_warecd, ed_mwarecd];
  for (var i = 0; i < objCode.length; i++) {
    objCode[i].unbind('onkeyup');
    objCode[i].bind('onkeyup', scwin.upperCase);
  }

  //==============================================================================
  // Excel Export Format Setting
  //==============================================================================
  var objGrid = [gr_SellingFreightInfo_freight, gr_PartnerFreightInfo_freight, gr_BuyingFreightInfo_freight];

  // Grid ExcelFormat
  var dataTypeNum = ['number', 'float', 'bigDecimal'];
  var dataType, displayFormat;
  for (var i = 0; i < objGrid.length; i++) {
    var column = objGrid[i].element.getElementsByTagName('w2:gBody')[0].getElementsByTagName('w2:column');
    for (var j = 0; j < column.length; j++) {
      dataType = column[j].getAttribute('dataType');
      if (dataTypeNum.includes(dataType)) {
        if (!column[j].getAttribute('excelCellType')) {
          column[j].setAttribute('excelCellType', 'number');
        }
        if (!column[j].getAttribute('excelFormat')) {
          displayFormat = column[j].getAttribute('displayFormat');
          if (displayFormat) {
            var temp = displayFormat.split('.');
            if (temp.length == 2) {
              if (temp[1].endsWith('0')) {
                displayFormat = temp[0] + '.' + '0'.padEnd(temp[1].length, '0');
              } else {
                displayFormat = temp[0] + '.' + temp[1].substring(0, temp[1].length - 1) + '0';
              }
            }
            column[j].setAttribute('excelFormat', displayFormat);
          }
        }
      }
    }
  }
};

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = function () {
  const codeOptions = [{
    grpCd: "IL005",
    compID: "lc_inco"
  }, {
    grpCd: "ZZ006",
    compID: "gr_SellingFreightInfo_freight:crcCd"
  }, {
    grpCd: "ZZ006",
    compID: "gr_PartnerFreightInfo_freight:crcCd"
  }, {
    grpCd: "ZZ006",
    compID: "gr_BuyingFreightInfo_freight:crcCd"
  }, {
    grpCd: "ZZ006",
    compID: "lc_cucd_freight"
  }];
  $c.data.setCommonCode($p, codeOptions, async function () {
    scwin.f_initSetTab();
    scwin.f_Set("INIT");
    await scwin.f_getParametrSetting();
    dma_HouseBillSearch.undo();
    if (scwin.f_OnLoad_freight) {
      scwin.f_OnLoad_freight();
    }
  });
};

//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = async function () {
  var kcomcd = scwin.p_kcomcd;
  var blno = scwin.p_blno;
  var type = scwin.p_type;
  var mblno = scwin.p_mblno;
  scwin.linkType = type;
  if ($c.str.trim($p, scwin.linkType) == "HawbCreate") {
    if (mblno == "null" || mblno == "") {
      return false;
    }
    scwin.f_Create();
    scwin.hd_kcomcd = kcomcd;
    ed_mblno.setValue(mblno);
    await scwin.f_MasterConsolNoLoading();
    if (scwin.actionFlag == "Create") {
      scwin.f_RetrieveMasterInfo();
    }
    ed_blno.focus();
  } else if ($c.str.trim($p, scwin.linkType) == "ColoadHawbCreate") {
    if (mblno == "null" || mblno == "") {
      return false;
    }
    scwin.f_Create();
    scwin.hd_kcomcd = kcomcd;
    ed_mblno.setValue(mblno);
    await scwin.f_MasterConsolNoLoading();
    if (scwin.actionFlag == "Create") {
      scwin.f_RetrieveMasterBookinInfo();
    }
    ed_blno.focus();
  } else if ($c.str.trim($p, scwin.linkType) == "HawbRetrieve") {
    if (blno == "null" || blno == "") {
      return false;
    }
    scwin.hd_kcomcd = kcomcd;
    ed_blno.setValue(blno);
    await scwin.f_MhnoLoading();
    await scwin.f_Retrieve();
  } else {
    if (blno == "null" || blno == "") {
      return false;
    }
    scwin.hd_kcomcd = kcomcd;
    ed_blno.setValue(blno);
    await scwin.f_MhnoLoading();
    await scwin.f_Retrieve();
  }
};
