//-------------------------------------------------------------------------
//조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding = function (ds, gubun) {
  switch (gubun) {
    case "HouseBillSearch":
      ds.setArray([]);
      ds.set("kcomcd", scwin.hd_kcomcd);
      ds.set("blno", $c.str.trim($p, ed_blno.getValue()));
      ds.set("mhno", lc_hmhno.getValue());
      ds.set("iogb", scwin.hd_iogb);
      break;
    case "HouseBillSave":
      ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
      ds.setCellData(ds.getRowPosition(), "iogb", scwin.hd_iogb);
      ds.setCellData(ds.getRowPosition(), "blno", $c.str.trim($p, ed_blno.getValue()));
      ds.setCellData(ds.getRowPosition(), "mhno", lc_hmhno.getValue());
      break;
    case "HouseLicenseSave":
      ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
      ds.setCellData(ds.getRowPosition(), "blno", $c.str.trim($p, ed_blno.getValue()));
      ds.setCellData(ds.getRowPosition(), "mhno", lc_hmhno.getValue());
      break;
    case "CustomerBookingSearch":
      ds.setArray([]);
      ds.set("kcomcd", scwin.hd_kcomcd);
      ds.set("srno", $c.str.trim($p, ed_srno.getValue()));
      ds.set("iogb", scwin.hd_iogb);
      break;
    case "HouseBillCheck":
      ds.setArray([]);
      ds.set("kcomcd", scwin.hd_kcomcd);
      ds.set("blno", $c.str.trim($p, ed_blno.getValue()));
      ds.set("iogb", scwin.hd_iogb);
      break;
    case "RetrieveMasterInfo":
      ds.setArray([]);
      ds.set("kcomcd", scwin.hd_kcomcd);
      ds.set("iogb", scwin.hd_iogb);
      ds.set("blno", $c.str.trim($p, ed_mblno.getValue()));
      break;
    case "MasterBillSearch":
      ds.setArray([]);
      ds.set("kcomcd", scwin.hd_kcomcd);
      ds.set("blno", $c.str.trim($p, ed_mblno.getValue()));
      ds.set("mhno", lc_hmhno.getValue());
      ds.set("iogb", scwin.hd_iogb);
      break;
    case "HouseFreightSave":
      ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
      ds.setCellData(ds.getRowPosition(), "iogb", scwin.hd_iogb);
      ds.setCellData(ds.getRowPosition(), "blno", $c.str.trim($p, ed_blno.getValue()));
      ds.setCellData(ds.getRowPosition(), "mhno", lc_hmhno.getValue());
      break;
    default:
      break;
  }
};

