//유효성검사
scwin.f_ReqFieldChk = async function () {
  if (ed_blno.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House B/L No"]);
    ed_blno.focus();
    return false;
  }
  if (ed_mblno.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Master B/L No"]);
    ed_mblno.focus();
    return false;
  }
  if (txt_shnm1.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Shipper Name"]);
    txt_shnm1.focus();
    return false;
  }
  if (txt_shnm2.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Shipper Name"]);
    txt_shnm2.focus();
    return false;
  }
  if (txt_cnnm1.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consignee Name"]);
    txt_cnnm1.focus();
    return false;
  }
  if (txt_cnnm2.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consignee Name"]);
    txt_cnnm2.focus();
    return false;
  }
  if (ed_ondt.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Onboard Date"]);
    ed_ondt.focus();
    return false;
  }
  if (ed_avdt.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Arrival Date"]);
    ed_avdt.focus();
    return false;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_ondt.getValue(), ed_avdt.getValue())) {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_048, ["Onboard Date", "Arrival Date"]);
    ed_ondt.focus();
    return false;
  }
  if ($c.gus.cfMonthsBetween($p, scwin.strCurDate.toDate(), ed_ondt.getValue().toDate()) > 3) {
    $c.win.alert($p, "Onboard Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }
  if ($c.gus.cfMonthsBetween($p, scwin.strCurDate.toDate(), ed_avdt.getValue().toDate()) > 3) {
    $c.win.alert($p, "Arrival Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_avdt.focus();
    return false;
  }
  if ($c.gus.cfYearsBetween($p, ed_ondt.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
    $c.win.alert($p, "Onboard Date가 3년 이상의 과거 일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }
  if ($c.gus.cfYearsBetween($p, ed_avdt.getValue().toDate(), scwin.strCurDate.toDate()) > 3) {
    $c.win.alert($p, "Arrival Date가 3년 이상의 과거 일 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_avdt.focus();
    return false;
  }
  if ($c.date.diffDate($p, ed_ondt.getValue(), ed_avdt.getValue()) > 149) {
    $c.win.alert($p, "Onboard Date-Arrival Date(transit time)가 150일을 초과할 수 없습니다.");
    tab_main.setSelectedTabIndex(0);
    ed_ondt.focus();
    return false;
  }
  if ($c.str.trim($p, ed_dept.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Department Info"]);
    ed_dept.focus();
    return false;
  }
  if ($c.str.trim($p, ed_sacd.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Salesman Info"]);
    ed_sacd.focus();
    return false;
  }
  if ($c.str.trim($p, ed_itcd.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Item Info"]);
    ed_itcd.focus();
    return false;
  }
  if ($c.str.trim($p, txt_ngnm1.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["EDI Item Info"]);
    txt_ngnm1.focus();
    return false;
  }
  if ($c.str.trim($p, ed_cjdt.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Result Date Date"]);
    ed_cjdt.focus();
    return false;
  }
  if ($c.str.trim($p, ed_dept.getValue()) == "1GG") {
    await $c.gus.cfAlertMsg($p, scwin.E_MSG_LO_WRN_010, ["Department Info"]);
    ed_dept.focus();
    return false;
  }
  if (lc_contractNo.getValue() == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Contract No"]);
    lc_contractNo.focus();
    return false;
  }
  scwin._execDataId(ds_customerInfo, "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveCustomerInfo&param1=" + $c.str.trim($p, ed_ascd.getValue()));
  if (ds_customerInfo.getRowCount() > 0) {
    if (ed_dept.getValue() != ds_customerInfo.getCellData(ds_customerInfo.getRowPosition(), "col1")) {
      await $c.gus.cfAlertMsg($p, scwin.E_MSG_LO_WRN_013);
      ed_dept.focus();
      return false;
    }
  }
  if (!(await $c.gus.cfValidate($p, [ed_blno, lc_hmhno, lc_shipGb, ed_mblno]))) {
    return false;
  }
  if (!(await $c.gus.cfValidate($p, [ed_ontime, ed_avtime], null, true))) {
    return false;
  }
  if (!(await $c.gus.cfValidate($p, [gr_SellingFreightInfo_freight, gr_PartnerFreightInfo_freight, gr_BuyingFreightInfo_freight], [], true))) {
    return false;
  }
  return true;
};

