scwin.f_Delete = async function () {
  await scwin.f_Delete_freight();
  if (scwin.spRtn == "0") {
    await scwin.f_InvoiceCheck_All("F");
    if (scwin.spRtn == "0") {
      scwin._deleteMarkedRows(ds_HouseBillInfo);
      scwin._deleteMarkedRows(ds_CustomerBookingInfo_booking);
      if (ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition(), "shipgb") == "D") {
        scwin._deleteMarkedRows(ds_MasterBL_master);
      }
      scwin.actionFlag = "Delete";
      var e = await $c.sbm.execute($p, sbm_Delete);
      if (scwin.sbm_Delete_submitdone) await scwin.sbm_Delete_submitdone();
      ed_blno.setValue("");
      lc_hmhno.setValue("");
      ds_hmhno.removeAll();
      ed_blno.focus();
    } else {
      await $c.gus.cfAlertMsg($p, scwin.E_MSG_LO_WRN_005);
    }
  }
};

//---------------------------------------------------------
// Tab Menu 선택시 처리
//---------------------------------------------------------
scwin.f_selectTabMenu = function (idx) {
  switch (idx) {
    case 0:
      // Header tab
      buttonTable.setStyle("display", "flex");
      buttonTable1.setStyle("display", "flex");
      break;
    case 1:
      // Container tab
      buttonTable.setStyle("display", "flex");
      buttonTable1.setStyle("display", "flex");
      break;
    case 2:
      // Freight tab
      buttonTable.setStyle("display", "none");
      buttonTable1.setStyle("display", "none");
      break;
    default:
      break;
  }
};

