// Master 정보 House 화면에 Binding
scwin.f_MasterInfoBinding = function () {
  var rowH = ds_HouseBillInfo.getRowPosition();
  var rowM = ds_MasterInfo.getRowPosition();
  var fltno = ds_MasterInfo.getCellData(rowM, "fltno") || "";
  ds_HouseBillInfo.setCellData(rowH, "dpcd", ds_MasterInfo.getCellData(rowM, "dpcd"));
  ds_HouseBillInfo.setCellData(rowH, "dpnm", ds_MasterInfo.getCellData(rowM, "dpnm"));
  ds_HouseBillInfo.setCellData(rowH, "dscd1", ds_MasterInfo.getCellData(rowM, "dstn"));
  ds_HouseBillInfo.setCellData(rowH, "dstn", ds_MasterInfo.getCellData(rowM, "dstn"));
  ds_HouseBillInfo.setCellData(rowH, "dsnm1", ds_MasterInfo.getCellData(rowM, "dsnm1"));
  ds_HouseBillInfo.setCellData(rowH, "fltno", fltno);
  ds_HouseBillInfo.setCellData(rowH, "ptcd1", fltno.substring(0, 2));
  ds_HouseBillInfo.setCellData(rowH, "ondt", ds_MasterInfo.getCellData(rowM, "ondt"));
  ds_HouseBillInfo.setCellData(rowH, "cjdt", ds_MasterInfo.getCellData(rowM, "ondt"));
  ds_HouseBillInfo.setCellData(rowH, "ontime", ds_MasterInfo.getCellData(rowM, "ontm"));
  ds_HouseBillInfo.setCellData(rowH, "avdt", ds_MasterInfo.getCellData(rowM, "avdt"));
  ds_HouseBillInfo.setCellData(rowH, "avtime", ds_MasterInfo.getCellData(rowM, "avtm"));
  if ($c.str.trim($p, ed_nocd.getValue()) == "") {
    ed_nocd.setValue(ds_MasterInfo.getCellData(rowM, "CNCD"));
    if ($c.str.trim($p, ed_nocd.getValue()) != "") {
      scwin.f_PopUp("Partner", "T", "F", "F");
    }
  }
  scwin.f_DestinationCheck();
  if ($c.str.trim($p, ed_ctcd.getValue()).length > 0) {
    scwin.f_OpenCommonPopUp("Country", "T", "F", "F");
  }
};
