scwin.f_ProcessBinding_freight = function (ds, gubun) {
  switch (gubun) {
    case "FreightSearch":
      if (ds.undo) ds.undo();
      if (ds.set) {
        ds.set("kcomcd", scwin.hd_kcomcd);
        ds.set("blno", $c.str.trim($p, ed_blno.getValue()));
        ds.set("mhno", $c.str.trim($p, lc_hmhno.getValue()));
        ds.set("iogb", scwin.hd_iogb);
        ds.set("mblHblCls", "H");
      } else {
        scwin._clearDataList(ds);
        idx = scwin._insertRow(ds);
        var row = ds.getRowPosition();
        ds.setCellData(idx, "kcomcd", scwin.hd_kcomcd);
        ds.setCellData(idx, "blno", $c.str.trim($p, ed_blno.getValue()));
        ds.setCellData(idx, "mhno", $c.str.trim($p, lc_hmhno.getValue()));
        ds.setCellData(idx, "iogb", scwin.hd_iogb);
        ds.setCellData(idx, "mblHblCls", "H");
      }
      break;
    case "FreightSave":
      if (ds.set) {
        ds.set("kcomcd", scwin.hd_kcomcd);
        ds.set("blno", $c.str.trim($p, ed_blno.getValue()));
      } else {
        ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
        ds.setCellData(ds.getRowPosition(), "blno", $c.str.trim($p, ed_blno.getValue()));
      }
      break;
    default:
      break;
  }
};

