scwin.f_Retrieve_freight = async function () {
  scwin.actionFlag = "Retrieve";
  if ($c.str.trim($p, ed_blno.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["House B/L No"]);
    ed_blno.focus();
    return false;
  }
  if ($c.str.trim($p, lc_hmhno.getValue()) == "") {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, ["Consol No"]);
    ed_blno.focus();
    return false;
  }
  scwin.f_ProcessBinding_freight(dma_SearchInfo_freight, "FreightSearch");
  scwin._clearDataList(ds_HouseFreightInfo_freight);
  scwin._clearDataList(ds_SellingFreightInfo_freight);
  scwin._clearDataList(ds_PartnerFreightInfo_freight);
  scwin._clearDataList(ds_BuyingFreightInfo_freight);
  await $c.sbm.execute($p, sbm_Retrieve_freight);
  await scwin.sbm_Retrieve_freight_submitdone();
  scwin._clearDataList(ds_profit_freight);
  await $c.sbm.execute($p, sbm_RetrieveProfit_freight);
  ds_HouseFreightInfo_freight.setRowPosition(0);
  ds_profit_freight.setRowPosition(0);
  if (gr_SellingFreightInfo_freight && gr_SellingFreightInfo_freight.setHeaderDisabled) {
    gr_SellingFreightInfo_freight.setHeaderDisabled("chk", true);
  }
  if (gr_PartnerFreightInfo_freight && gr_PartnerFreightInfo_freight.setHeaderDisabled) {
    gr_PartnerFreightInfo_freight.setHeaderDisabled("chk", true);
  }
  if (gr_BuyingFreightInfo_freight && gr_BuyingFreightInfo_freight.setHeaderDisabled) {
    gr_BuyingFreightInfo_freight.setHeaderDisabled("chk", true);
  }
};

