  if (ds_HouseFreightInfo_freight.undoAll) ds_HouseFreightInfo_freight.undoAll();
  if (ds_BuyingFreightInfo_freight.undoAll) ds_BuyingFreightInfo_freight.undoAll();
  if (ds_SellingFreightInfo_freight.undoAll) ds_SellingFreightInfo_freight.undoAll();
