//행추가
scwin.f_AddRowMulti_freight = function (gubun) {
  var rowMakeSelling = parseInt($c.str.trim($p, ed_rowMake_selling.getValue() || "1"), 10);
  var rowMakePartner = parseInt($c.str.trim($p, ed_rowMake_partner.getValue() || "1"), 10);
  var rowMakeBuying = parseInt($c.str.trim($p, ed_rowMake_buying.getValue() || "1"), 10);
  if (isNaN(rowMakeSelling) || rowMakeSelling < 1) rowMakeSelling = 1;
  if (isNaN(rowMakePartner) || rowMakePartner < 1) rowMakePartner = 1;
  if (isNaN(rowMakeBuying) || rowMakeBuying < 1) rowMakeBuying = 1;
  switch (gubun) {
    case "Selling":
      for (var i = 0; i < rowMakeSelling; i++) {
        scwin.f_AddRow_freight("Selling");
      }
      break;
    case "Partner":
      for (var j = 0; j < rowMakePartner; j++) {
        scwin.f_AddRow_freight("Partner");
      }
      break;
    case "Buying":
      for (var k = 0; k < rowMakeBuying; k++) {
        scwin.f_AddRow_freight("Buying");
      }
      break;
    default:
      break;
  }
  scwin.f_TotalCac_freight(gubun);
};
scwin.f_DeleteAllRow_freight = async function (gubun) {
  var ds = null;
  switch (gubun) {
    case "Selling":
      ds = ds_SellingFreightInfo_freight;
      break;
    case "Partner":
      ds = ds_PartnerFreightInfo_freight;
      break;
    case "Buying":
      ds = ds_BuyingFreightInfo_freight;
      break;
    default:
      return;
  }
  for (var i = ds.getRowCount() - 1; i > -1; i--) {
    ds.setRowPosition(i);
    await scwin.f_DeleteRow_freight(gubun);
  }
};

//-------------------------------------------------------------------------
// function name : f_DelRow
// function desc : 그리드  행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow_freight = async function (gubun) {
  var tmp = null;
  switch (gubun) {
    case "Selling":
      tmp = ds_SellingFreightInfo_freight;
      break;
    case "Partner":
      tmp = ds_PartnerFreightInfo_freight;
      break;
    case "Buying":
      tmp = ds_BuyingFreightInfo_freight;
      break;
    default:
      return;
  }
  var rowPos = tmp.getRowPosition();
  if (rowPos < 0) rowPos = 0;
  for (var i = 0; i < tmp.getRowCount(); i++) {
    if (tmp.getCellData(i, "chk") == "T" || i === rowPos) {
      var certiCol = gubun === "Buying" ? "pchsCertiNo" : "certiNo";
      if ($c.str.trim($p, tmp.getCellData(i, certiCol)) === "") {
        scwin._deleteRowByStatus(tmp, i);
      } else {
        await $c.gus.cfAlertMsg($p, scwin.E_MSG_CM_ERR_041 || E_MSG_CM_ERR_041, ["Invoice No", "delete   " + i]);
        return;
      }
    }
  }
  scwin.f_TotalCac_freight(gubun);
};

//행취소
scwin.f_UndoRow_freight = function (gubun) {
  var ds = null;
  switch (gubun) {
    case "Selling":
      ds = ds_SellingFreightInfo_freight;
      break;
    case "Partner":
      ds = ds_PartnerFreightInfo_freight;
      break;
    case "Buying":
      ds = ds_BuyingFreightInfo_freight;
      break;
    default:
      return;
  }
  if (ds.undoMarked) {
    ds.undoMarked();
    return;
  }
  for (var i = 0; i < ds.getRowCount(); i++) {
    if (ds.getCellData(i, "chk") == "T") {
      if ($c.data.undoRow) {
        $c.data.undoRow($p, ds, i);
      }
    }
  }
};

