//MHNNO 가져오기
scwin.f_MhnoLoading_freight = async function () {
  var strClntNo = $c.str.trim($p, ed_blno.getValue());
  if (strClntNo.length > 0) {
    var param1 = strClntNo;
    await scwin._execDataId(ds_hmhno, "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retriveAirHouseMhnoListCombo&param1=" + param1 + "&param2=" + scwin.hd_iogb);
  } else {
    lc_hmhno.setValue("");
    ds_hmhno.removeAll();
  }
};

// 환율정보가져오기
scwin.f_ExrateLoading_freight = async function (param1, param2, param3) {
  if (!$c.str.trim($p, param1)) return;
  var crc = param1;
  if (crc == "KRW") crc = "USD";
  await scwin._execDataId(ds_ExRate_freight, "/cm.zz.RetrieveComboCMD.do?sysCd=ilCommonEBC&queryId=retrieveExRate&param1=" + crc + "&param2=" + param2 + "&param3=" + param3);
};
scwin.f_PkgWegihtSetting_freight = function (row, colid, gubun) {
  switch (gubun) {
    case "Selling":
      {
        if (colid == "fareEngCd") {
          ds_SellingFreightInfo_freight.setCellData(row, "grossWt", ds_HouseFreightInfo_freight.getCellData(0, "mftwht"));
          ds_SellingFreightInfo_freight.setCellData(row, "chgWt", ds_HouseFreightInfo_freight.getCellData(0, "tcwht"));
        }
        break;
      }
    case "Partner":
      {
        if (colid == "fareEngCd") {
          ds_PartnerFreightInfo_freight.setCellData(row, "grossWt", 0);
          ds_PartnerFreightInfo_freight.setCellData(row, "chgWt", ds_HouseFreightInfo_freight.getCellData(0, "tcwht"));
        }
        break;
      }
    case "Buying":
      {
        if (colid == "fareEngCd") {
          ds_BuyingFreightInfo_freight.setCellData(row, "grossWt", ds_HouseFreightInfo_freight.getCellData(0, "mftwht"));
          ds_BuyingFreightInfo_freight.setCellData(row, "chgWt", ds_HouseFreightInfo_freight.getCellData(0, "tcwht"));
        }
        break;
      }
    default:
      break;
  }
};
scwin.f_RateAmount_freight = function (row, colid, gubun, olddata) {
  var checkNumCol, checkValCol, dsObj;
  var validNum = 0;
  switch (gubun) {
    case "Selling":
      {
        dsObj = ds_SellingFreightInfo_freight;
        checkNumCol = ["sellUpr", "qty", "sellAmt", "sellAmtFcrc", "exRate"];
        checkValCol = ["sellAmt", "vatAmt", "sellAmtFcrc"];
        var crcCd = ds_SellingFreightInfo_freight.getCellData(row, "crcCd");
        var nUnit = scwin.f_Currency_Unit_freight(crcCd);
        if (colid == "sellUpr" || colid == "qty") {
          var cweight = Number(ds_SellingFreightInfo_freight.getCellData(row, "qty"));
          var exrate = Number(ds_SellingFreightInfo_freight.getCellData(row, "exRate"));
          if (crcCd == "KRW") {
            var amount = Math.round(cweight * Number(ds_SellingFreightInfo_freight.getCellData(row, "sellUpr")));
            var vatAmt = ds_SellingFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amount * 0.1);
            ds_SellingFreightInfo_freight.setCellData(row, "sellAmt", amount);
            ds_SellingFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
            ds_SellingFreightInfo_freight.setCellData(row, "sellAmtFcrc", 0);
          } else {
            var amountF = Math.round(cweight * Number(ds_SellingFreightInfo_freight.getCellData(row, "sellUpr")) * 100) / 100;
            var vatAmt = ds_SellingFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amountF * exrate / nUnit * 0.1);
            ds_SellingFreightInfo_freight.setCellData(row, "sellAmt", Math.round(amountF * exrate / nUnit));
            ds_SellingFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
            ds_SellingFreightInfo_freight.setCellData(row, "sellAmtFcrc", amountF);
          }
        } else if (colid == "sellAmt") {
          var exrate2 = Number(ds_SellingFreightInfo_freight.getCellData(row, "exRate"));
          var amount2 = Number(ds_SellingFreightInfo_freight.getCellData(row, "sellAmt"));
          var vatAmt = ds_SellingFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amount2 * 0.1);
          ds_SellingFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
          if (crcCd == "KRW") {
            ds_SellingFreightInfo_freight.setCellData(row, "sellAmtFcrc", 0);
          } else {
            ds_SellingFreightInfo_freight.setCellData(row, "sellAmtFcrc", Math.round(amount2 * nUnit / exrate2 * 100) / 100);
          }
        } else if (colid == "sellAmtFcrc" || colid == "exRate") {
          var exrate3 = ds_SellingFreightInfo_freight.getCellData(row, "exRate");
          var amount3 = ds_SellingFreightInfo_freight.getCellData(row, "sellAmtFcrc");
          var vatAmt = ds_SellingFreightInfo_freight.getCellData(row, "vatYn") == 0 ? 0 : Math.round(amount3 * exrate3 / nUnit * 0.1);
          ds_SellingFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
          ds_SellingFreightInfo_freight.setCellData(row, "sellAmt", Math.round(amount3 * exrate3 / nUnit));
        }

        // 유효한 숫자로 적재
        if (checkNumCol.includes(colid)) {
          for (var i = 0; i < checkValCol.length; i++) {
            validNum = scwin.getValidNumber(ds_SellingFreightInfo_freight.getCellData(row, checkValCol[i]));
            ds_SellingFreightInfo_freight.setCellData(row, checkValCol[i], validNum);
          }
        }
        break;
      }
    case "Partner":
      {
        dsObj = ds_PartnerFreightInfo_freight;
        checkNumCol = ["sellUpr", "qty", "sellAmt", "sellAmtFcrc", "exRate"];
        checkValCol = ["sellAmt", "vatAmt", "sellAmtFcrc", "sellUpr"];
        var crcCd = ds_PartnerFreightInfo_freight.getCellData(row, "crcCd");
        var nUnitP = scwin.f_Currency_Unit_freight(crcCd);
        if (colid == "sellUpr" || colid == "qty") {
          var cweightP = Number(ds_PartnerFreightInfo_freight.getCellData(row, "qty"));
          var exrateP = Number(ds_PartnerFreightInfo_freight.getCellData(row, "exRate"));
          if (crcCd == "KRW") {
            var amountP = Math.round(cweightP * Number(ds_PartnerFreightInfo_freight.getCellData(row, "sellUpr")));
            var vatAmt = ds_PartnerFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amountP * 0.1);
            ds_PartnerFreightInfo_freight.setCellData(row, "sellAmt", amountP);
            ds_PartnerFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
            ds_PartnerFreightInfo_freight.setCellData(row, "sellAmtFcrc", Math.round(amountP * nUnitP / exrateP * 100) / 100);
          } else {
            var amountPF = Math.round(cweightP * Number(ds_PartnerFreightInfo_freight.getCellData(row, "sellUpr")) * 100) / 100;
            var vatAmt = ds_PartnerFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amountPF * exrateP / nUnitP * 0.1);
            ds_PartnerFreightInfo_freight.setCellData(row, "sellAmt", Math.round(amountPF * exrateP / nUnitP));
            ds_PartnerFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
            ds_PartnerFreightInfo_freight.setCellData(row, "sellAmtFcrc", amountPF);
          }
        } else if (colid == "sellAmt") {
          var exrateP2 = Number(ds_PartnerFreightInfo_freight.getCellData(row, "exRate"));
          var amountP2 = Number(ds_PartnerFreightInfo_freight.getCellData(row, "sellAmt"));
          var vatAmt = ds_PartnerFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amountP2 * 0.1);
          ds_PartnerFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
          ds_PartnerFreightInfo_freight.setCellData(row, "sellAmtFcrc", Math.round(amountP2 * nUnitP / exrateP2 * 100) / 100);
        } else if (colid == "sellAmtFcrc" || colid == "exRate") {
          var exrateP3 = Number(ds_PartnerFreightInfo_freight.getCellData(row, "exRate"));
          var amountP3 = Number(ds_PartnerFreightInfo_freight.getCellData(row, "sellAmtFcrc"));
          var vatAmt = ds_PartnerFreightInfo_freight.getCellData(row, "vatYn") == "0" ? 0 : Math.round(amountP3 * exrateP3 / nUnitP * 0.1);
          var cweightP3 = Number(ds_PartnerFreightInfo_freight.getCellData(row, "qty"));
          ds_PartnerFreightInfo_freight.setCellData(row, "sellAmt", Math.round(amountP3 * exrateP3 / nUnitP));
          ds_PartnerFreightInfo_freight.setCellData(row, "vatAmt", vatAmt);
          ds_PartnerFreightInfo_freight.setCellData(row, "sellUpr", Math.round((amountP3 / cweightP3 - 0.005) * 100) / 100);
        }
        break;
      }
    case "Buying":
      {
        dsObj = ds_BuyingFreightInfo_freight;
        checkNumCol = ["pchsUpr", "qty", "pchsAmt", "pchsAmtFcrc", "exRate"];
        checkValCol = ["prtnAmt", "pchsAmt", "vat", "pchsAmtFcrc", "pchsAmtFcrc", "vatAmt"];
        var crcCd = ds_BuyingFreightInfo_freight.getCellData(row, "crcCd");
        var nUnitB = scwin.f_Currency_Unit_freight(crcCd);
        if (colid == "pchsUpr" || colid == "qty") {
          var cweightB = Number(ds_BuyingFreightInfo_freight.getCellData(row, "qty"));
          var exrateB = Number(ds_BuyingFreightInfo_freight.getCellData(row, "exRate"));
          if (crcCd == "KRW") {
            var amountB = Math.round(cweightB * ds_BuyingFreightInfo_freight.getCellData(row, "pchsUpr"));
            ds_BuyingFreightInfo_freight.setCellData(row, "prtnAmt", amountB);
            ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmt", amountB);
            if (ds_BuyingFreightInfo_freight.getCellData(row, "vatYn") == "0") {
              ds_BuyingFreightInfo_freight.setCellData(row, "vat", 0);
            } else {
              ds_BuyingFreightInfo_freight.setCellData(row, "vat", Math.round(amountB * 0.1 - 0.5));
            }
            ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmtFcrc", 0);
          } else {
            var amountBF = Math.round(cweightB * ds_BuyingFreightInfo_freight.getCellData(row, "pchsUpr") * 100) / 100;
            ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmtFcrc", amountBF);
            ds_BuyingFreightInfo_freight.setCellData(row, "prtnAmt", Math.round(amountBF * exrateB / nUnitB));
            ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmt", Math.round(amountBF * exrateB / nUnitB));
            if (ds_BuyingFreightInfo_freight.getCellData(row, "vatYn") == "0") {
              ds_BuyingFreightInfo_freight.setCellData(row, "vat", 0);
            } else {
              ds_BuyingFreightInfo_freight.setCellData(row, "vat", Math.round(amountBF * exrateB / nUnitB * 0.1 - 0.5));
            }
          }
        } else if (colid == "pchsAmt") {
          var exrateB2 = Number(ds_BuyingFreightInfo_freight.getCellData(row, "exRate"));
          var amountB2 = Number(ds_BuyingFreightInfo_freight.getCellData(row, "pchsAmt"));
          if (ds_BuyingFreightInfo_freight.getCellData(row, "vatYn") == "0") {
            ds_BuyingFreightInfo_freight.setCellData(row, "vat", 0);
          } else {
            ds_BuyingFreightInfo_freight.setCellData(row, "vat", Math.round(amountB2 * 0.1 - 0.5));
          }
          if (crcCd == "KRW") {
            ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmtFcrc", 0);
          } else {
            ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmtFcrc", Math.round(amountB2 * nUnitB / exrateB2 * 100) / 100);
          }
        } else if (colid == "pchsAmtFcrc" || colid == "exRate") {
          var exrateB3 = Number(ds_BuyingFreightInfo_freight.getCellData(row, "exRate"));
          var amountB3 = Number(ds_BuyingFreightInfo_freight.getCellData(row, "pchsAmtFcrc"));
          ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmt", Math.round(amountB3 * exrateB3 / nUnitB));
          if (ds_BuyingFreightInfo_freight.getCellData(row, "vatYn") == "0") {
            ds_BuyingFreightInfo_freight.setCellData(row, "vatAmt", 0);
          } else {
            ds_BuyingFreightInfo_freight.setCellData(row, "vatAmt", Math.round(amountB3 * exrateB3 / nUnitB * 0.1));
          }
        }
        break;
      }
    default:
      break;
  }

  // 유효한 숫자로 적재
  if (checkNumCol.includes(colid)) {
    for (var i = 0; i < checkValCol.length; i++) {
      validNum = scwin.getValidNumber(dsObj.getCellData(row, checkValCol[i]));
      dsObj.setCellData(row, checkValCol[i], validNum);
    }
  }
};

