// Prepaid / Collect Summery 구하기
// Master Buying 금액만 Summery 에 포함 된다.
scwin.f_pcSummery_freight = function () {
  var pfchg = 0,
    cfchg = 0,
    cfuchg = 0;
  var pvchg = 0,
    cvchg = 0,
    cvuchg = 0;
  var pachg = 0,
    cachg = 0,
    cauchg = 0;
  var ptchg = 0,
    ctchg = 0,
    ctuchg = 0;
  for (var i = 0; i < ds_SellingFreightInfo_freight.getRowCount(); i++) {
    var status = ds_SellingFreightInfo_freight.getRowStatus(i);
    if (status != "D") {
      var crcCd = ds_SellingFreightInfo_freight.getCellData(i, "crcCd");
      var fareGrp = ds_SellingFreightInfo_freight.getCellData(i, "fareGrpCd");
      var sellAmtFcrc = ds_SellingFreightInfo_freight.getCellData(i, "sellAmtFcrc");
      var sellAmt = ds_SellingFreightInfo_freight.getCellData(i, "sellAmt");
      if (crcCd != "KRW" || fareGrp == "AF") {
        if (fareGrp != "CC") {
          cfuchg += Number(sellAmtFcrc);
          cfchg += Number(sellAmt);
        } else {
          cvuchg += Number(sellAmtFcrc);
          cvchg += Number(sellAmt);
        }
      } else {
        if (fareGrp != "CC") {
          cauchg += Number(sellAmtFcrc);
          cachg += Number(sellAmt);
        } else {
          cvuchg += Number(sellAmtFcrc);
          cvchg += Number(sellAmt);
        }
      }
    }
  }
  ed_pfchg_freight.setValue(pfchg);
  ed_pvchg_freight.setValue(pvchg);
  ed_pachg_freight.setValue(pachg);
  ed_ptchg_freight.setValue(pfchg + pvchg + pachg);
  ed_cfchg_freight.setValue(cfchg);
  ed_cvchg_freight.setValue(cvchg);
  ed_cachg_freight.setValue(cachg);
  ed_ctchg_freight.setValue(cfchg + cvchg + cachg);
  ed_cfuchg_freight.setValue(cfuchg);
  ed_cvuchg_freight.setValue(cvuchg);
  ed_cauchg_freight.setValue(cauchg);
  ed_ctuchg_freight.setValue(cfuchg + cvuchg + cauchg);
};
scwin.f_TotalCac_freight = function (gubun) {
  switch (gubun) {
    case "Selling":
      {
        var sellingUtotal = 0;
        var sellingTotal = 0;
        var sellingTotalVat = 0;
        if (ds_SellingFreightInfo_freight.getRowCount() > 0) {
          for (var i = 0; i < ds_SellingFreightInfo_freight.getRowCount(); i++) {
            var status = ds_SellingFreightInfo_freight.getRowStatus(i);
            if (status != "D") {
              sellingUtotal += Number(ds_SellingFreightInfo_freight.getCellData(i, "sellAmtFcrc") || 0);
              sellingTotal += Number(ds_SellingFreightInfo_freight.getCellData(i, "sellAmt") || 0);
              sellingTotalVat += Number(ds_SellingFreightInfo_freight.getCellData(i, "vatAmt") || 0);
            }
          }
          ed_Selling_utotal.setValue(sellingUtotal);
          ed_Selling_total_freight.setValue(sellingTotal);
          ed_Selling_total_freightVat.setValue(sellingTotalVat);
        }
        break;
      }
    case "Partner":
      {
        var partnerUtotal = 0;
        var partnerTotal = 0;
        var partnerTotalVat = 0;
        if (ds_PartnerFreightInfo_freight.getRowCount() > 0) {
          for (var j = 0; j < ds_PartnerFreightInfo_freight.getRowCount(); j++) {
            var pStatus = ds_PartnerFreightInfo_freight.getRowStatus(j);
            if (pStatus != "D") {
              partnerUtotal += Number(ds_PartnerFreightInfo_freight.getCellData(j, "sellAmtFcrc") || 0);
              partnerTotal += Number(ds_PartnerFreightInfo_freight.getCellData(j, "sellAmt") || 0);
              partnerTotalVat += Number(ds_PartnerFreightInfo_freight.getCellData(j, "vatAmt") || 0);
            }
          }
          ed_Partner_utotal.setValue(partnerUtotal);
          ed_Partner_total.setValue(partnerTotal);
          ed_Partner_totalVat.setValue(partnerTotalVat);
        }
        break;
      }
    case "Buying":
      {
        var buyingUtotal = 0;
        var buyingTotal = 0;
        var buyingTotalVat = 0;
        var buyingTotalVatSum = 0;
        if (ds_BuyingFreightInfo_freight.getRowCount() > 0) {
          for (var k = 0; k < ds_BuyingFreightInfo_freight.getRowCount(); k++) {
            var bStatus = ds_BuyingFreightInfo_freight.getRowStatus(k);
            if (bStatus != "D") {
              buyingUtotal += Number(ds_BuyingFreightInfo_freight.getCellData(k, "pchsAmtFcrc") || 0);
              buyingTotal += Number(ds_BuyingFreightInfo_freight.getCellData(k, "pchsAmt") || 0);
              buyingTotalVat += Number(ds_BuyingFreightInfo_freight.getCellData(k, "vat") || 0);
            }
          }
          buyingTotalVatSum = buyingTotal + buyingTotalVat;
          ed_Buying_utotal.setValue(buyingUtotal);
          ed_Buying_total.setValue(buyingTotal);
          ed_Buying_totalVat.setValue(buyingTotalVat);
          ed_Buying_totalVatSum.setValue(buyingTotalVatSum);
        }
        break;
      }
    default:
      break;
  }
};
