  var dpcd = ds_HouseFreightInfo_freight.getCellData(houseRow, "dpcd");
  var dscd = ds_HouseFreightInfo_freight.getCellData(houseRow, "dstn");
  var carrier = ds_HouseFreightInfo_freight.getCellData(houseRow, "carrier");
  var partner = "";
  var blgb = "";
