scwin.f_RetrieveTmp_freight = async function () {
  if (dma_tmpCnd_freight && dma_tmpCnd_freight.undo) {
    dma_tmpCnd_freight.undo();
  }
  if ($c.str.trim($p, ed_blnoTmp_freight.getValue()) == "") {
    await $c.win.alert($p, "선조회할 BL번호가 없습니다");
    return false;
  }
  dma_tmpCnd_freight.set("blno", $c.str.trim($p, ed_blnoTmp_freight.getValue()));
  var idx = scwin.TabIndex;
  if (idx == 0) {
    dma_tmpCnd_freight.set("rtrvTypCd", "SELLING");
    if (ds_SellingFreightInfo_freight.getRowCount() > 0) {
      await $c.win.alert($p, "이미 매출이 등록된 건은 선조회 할 수 없습니다");
      return false;
    }
    if (typeof sbm_RetrieveTmpSelling_freight !== "undefined") {
      await $c.sbm.execute($p, sbm_RetrieveTmpSelling_freight);
      scwin.sbm_RetrieveTmp_freight_submitdone();
    }
  } else if (idx == 1) {
    dma_tmpCnd_freight.set("rtrvTypCd", "PARTNER");
    if (ds_PartnerFreightInfo_freight.getRowCount() > 0) {
      await $c.win.alert($p, "이미 PARTNER 실적이 등록된 건은 선조회 할 수 없습니다");
      return false;
    }
    if (typeof sbm_RetrieveTmpPartner_freight !== "undefined") {
      await $c.sbm.execute($p, sbm_RetrieveTmpPartner_freight);
      scwin.sbm_RetrieveTmp_freight_submitdone();
    }
  } else if (idx == 2) {
    dma_tmpCnd_freight.set("rtrvTypCd", "BUYING");
    if (ds_BuyingFreightInfo_freight.getRowCount() > 0) {
      await $c.win.alert($p, "이미 매입이 등록된 건은 선조회 할 수 없습니다");
      return false;
    }
    if (typeof sbm_RetrieveTmpBuying_freight !== "undefined") {
      await $c.sbm.execute($p, sbm_RetrieveTmpBuying_freight);
      scwin.sbm_RetrieveTmp_freight_submitdone();
    }
  }
};

