scwin.f_JobCloseYn = async function () {
  var preWrkNo = "FI01";
  var minRsltsDt = (scwin.strCurDate || "").substring(0, 6);
  for (var i = 0; i < ds_SellingFreightInfo_freight.getRowCount(); i++) {
    var st = ds_SellingFreightInfo_freight.getRowStatus(i);

    // 운임 신규 생성일 경우
    if (st == "C") {
      var rsltsStdDt = ds_SellingFreightInfo_freight.getCellData(i, "rsltsStdDt");
      if (rsltsStdDt && rsltsStdDt.substring(0, 6) < minRsltsDt) {
        minRsltsDt = rsltsStdDt.substring(0, 6);
      }
      var isClose = await scwin.cfJobCloseYN("CUR", minRsltsDt, "00", preWrkNo, "0", "", "", "000");
      if (isClose == "2" || isClose == "DNF") {
        await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nSelling List Result Date를 확인하세요.");
        return false;
      }
    }
  }
  minRsltsDt = (scwin.strCurDate || "").substring(0, 6);
  for (var j = 0; j < ds_PartnerFreightInfo_freight.getRowCount(); j++) {
    var st2 = ds_PartnerFreightInfo_freight.getRowStatus(j);

    // 운임 신규 생성일 경우
    if (st2 == "C") {
      var rsltsStdDt2 = ds_PartnerFreightInfo_freight.getCellData(j, "rsltsStdDt");
      if (rsltsStdDt2 && rsltsStdDt2.substring(0, 6) < minRsltsDt) {
        minRsltsDt = rsltsStdDt2.substring(0, 6);
      }
      var isClose2 = await scwin.cfJobCloseYN("CUR", minRsltsDt, "00", preWrkNo, "0", "", "", "000");
      if (isClose2 == "2" || isClose2 == "DNF") {
        await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nPartner List Result Date를 확인하세요.");
        return false;
      }
    }
  }
  minRsltsDt = (scwin.strCurDate || "").substring(0, 6);
  for (var k = 0; k < ds_BuyingFreightInfo_freight.getRowCount(); k++) {
    var st3 = ds_BuyingFreightInfo_freight.getRowStatus(k);

    // 운임 신규 생성일 경우
    if (st3 == "C") {
      var rsltsStdDt3 = ds_BuyingFreightInfo_freight.getCellData(k, "rsltsStdDt");
      if (rsltsStdDt3 && rsltsStdDt3.substring(0, 6) < minRsltsDt) {
        minRsltsDt = rsltsStdDt3.substring(0, 6);
      }
      var isClose3 = await scwin.cfJobCloseYN("CUR", minRsltsDt, "00", preWrkNo, "0", "", "", "000");
      if (isClose3 == "2" || isClose3 == "DNF") {
        await $c.gus.cfAlertMsg($p, "회계마감 된 날짜로는 Result Date를 입력할 수 없습니다.  \nBuying List Result Date를 확인하세요.");
        return false;
      }
    }
  }
  return true;
};
