scwin.sbm_Retrieve_freight_submitdone = async function (e) {
  // RowPosition 설정
  scwin.setOutDSRowPosition(sbm_Retrieve_freight);
  if (ds_HouseFreightInfo_freight.getRowCount() == 0) {
    scwin.f_ProcessResult_freight("None");
  } else {
    scwin.f_ProcessResult_freight("FreightInfo");
  }
  if (scwin.v_linkcheck == 9) {
    scwin.f_Set_freight("UPDATE");
    var rowCnt = parseInt(scwin.p_row_cnt || "0", 10);
    var data = scwin.p_data || "";
    var rtnValues = data ? data.split("$") : [];
    for (var t = 0; t <= rowCnt - 1; t++) {
      if (rtnValues[t]) {
        rtnValues[t] = rtnValues[t].split("_");
      }
    }
    var k = ds_BuyingFreightInfo_freight.getRowCount();
    if (!rtnValues || rtnValues.length == 0) {
      return false;
    }
    for (var i = k; i < rtnValues.length + k; i++) {
      var idx = i - k;
      scwin.f_AddRow_freight("Buying");
      if (dma_frt_condition_freight && dma_frt_condition_freight.set) {
        dma_frt_condition_freight.set("fromCd", rtnValues[idx] ? rtnValues[idx][2] : "");
      }
      await $c.sbm.execute($p, sbm_retrieve_frtMapping_freight);
      var row = ds_BuyingFreightInfo_freight.getRowPosition();
      ds_BuyingFreightInfo_freight.setCellData(row, "fareEngCd", ds_frtMapping_freight.getCellData(0, "toCd"));
      ds_BuyingFreightInfo_freight.setCellData(row, "fareEngNm", ds_frtMapping_freight.getCellData(0, "description"));
      ds_BuyingFreightInfo_freight.setCellData(row, "selpchItemCd", ds_frtMapping_freight.getCellData(0, "dtlCd1"));
      ds_BuyingFreightInfo_freight.setCellData(row, "fareGrpCd", ds_frtMapping_freight.getCellData(0, "dtlCd2"));
      ds_BuyingFreightInfo_freight.setCellData(row, "vatYn", ds_frtMapping_freight.getCellData(0, "dtlCd3"));
      var vatYn = ds_BuyingFreightInfo_freight.getCellData(row, "vatYn");
      if (vatYn != 0) {
        var pchsAmt = Number(rtnValues[idx] ? rtnValues[idx][6] : 0) || 0;
        ds_BuyingFreightInfo_freight.setCellData(row, "vat", Math.round(pchsAmt * 0.1 - 0.5));
      }
      if (gr_BuyingFreightInfo_freight && gr_BuyingFreightInfo_freight.setColumn) {
        gr_BuyingFreightInfo_freight.setColumn("pchsTyp");
      }
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNo", rtnValues[idx] ? rtnValues[idx][0] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsClntNm", rtnValues[idx] ? rtnValues[idx][1] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "fareEngCd", rtnValues[idx] ? rtnValues[idx][2] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "crcCd", rtnValues[idx] ? rtnValues[idx][3] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmtFcrc", rtnValues[idx] ? rtnValues[idx][4] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "exRate", rtnValues[idx] ? rtnValues[idx][5] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsAmt", rtnValues[idx] ? rtnValues[idx][6] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "chgWt", rtnValues[idx] ? rtnValues[idx][7] : "");
      ds_BuyingFreightInfo_freight.setCellData(row, "pchsUpr", rtnValues[idx] ? rtnValues[idx][8] : "");
    }
    scwin.f_selectTabMenu_freight(2);
  }
  var exgbIdx = lc_exgb_freight && lc_exgb_freight.getSelectedIndex ? lc_exgb_freight.getSelectedIndex() : -1;
  if (exgbIdx === 0) {
    scwin.TabIndex = 2;
  } else if (exgbIdx === 1) {
    scwin.TabIndex = 1;
  } else if (exgbIdx === 2) {
    scwin.TabIndex = 0;
  }
};
