scwin.sbm_RetrieveTmp_freight_submitdone = function (e) {
  if (scwin.TabIndex == 0) scwin.f_pcSummery_freight();
  var dsHouse = ds_HouseFreightInfo_freight;
  gr_SellingFreightInfo_freight.setFocusedCell(0, 2);
  gr_PartnerFreightInfo_freight.setFocusedCell(0, 2);
  gr_BuyingFreightInfo_freight.setFocusedCell(0, 2);
  scwin.f_GridSet_freight("Retrieve");
  scwin.f_TotalCac_freight("Selling");
  scwin.f_TotalCac_freight("Partner");
  scwin.f_TotalCac_freight("Buying");
  if (!dsHouse || dsHouse.getRowCount() === 0) return;
  var houseRow = dsHouse.getRowPosition();
  if (houseRow < 0) houseRow = 0;
  var idx = scwin.TabIndex;
  idx = idx === "" || idx === null || typeof idx === "undefined" ? 0 : parseInt(idx, 10);
  if (idx === 0) {
    // Selling
    for (var i = 0; i < ds_SellingFreightInfo_freight.getRowCount(); i++) {
      scds_SellingFreightInfo_freight.setCellData(i, "odrNo", dsHouse.getCellData(houseRow, "odrNo"));
      scds_SellingFreightInfo_freight.setCellData(i, "kcomcd", scwin.hd_kcomcd);
      scds_SellingFreightInfo_freight.setCellData(i, "seaAirCls", scwin.hd_seaAirCls);
      scds_SellingFreightInfo_freight.setCellData(i, "blNo", $c.str.trim($p, ed_blno.getValue()));
      scds_SellingFreightInfo_freight.setCellData(i, "mhno", $c.str.trim($p, lc_hmhno.getValue()));
      scds_SellingFreightInfo_freight.setCellData(i, "locPtnCls", "1");
      scds_SellingFreightInfo_freight.setCellData(i, "mblHblCls", scwin.hd_mblHblCls);
      scds_SellingFreightInfo_freight.setCellData(i, "drcrCls", "D");
      scds_SellingFreightInfo_freight.setCellData(i, "rsltsStdDt", dsHouse.getCellData(houseRow, "cjdt"));
      ds_SellingFreightInfo_freight.modifyRowStatus(i, "C");
    }
    $c.gus.cfDisableBtnOnly($p, scwin._compact([grpBtn1]));
    $c.gus.cfDisableBtnOnly($p, scwin._compact([btn_Delete_freightRowSelling_freight]));
  } else if (idx === 1) {
    // Partner
    for (var j = 0; j < ds_PartnerFreightInfo_freight.getRowCount(); j++) {
      ds_PartnerFreightInfo_freight.setCellData(j, "odrNo", dsHouse.getCellData(houseRow, "odrNo"));
      ds_PartnerFreightInfo_freight.setCellData(j, "kcomcd", scwin.hd_kcomcd);
      ds_PartnerFreightInfo_freight.setCellData(j, "seaAirCls", scwin.hd_seaAirCls);
      ds_PartnerFreightInfo_freight.setCellData(j, "blNo", $c.str.trim($p, ed_blno.getValue()));
      ds_PartnerFreightInfo_freight.setCellData(j, "mhno", $c.str.trim($p, lc_hmhno.getValue()));
      ds_PartnerFreightInfo_freight.setCellData(j, "locPtnCls", "2");
      ds_PartnerFreightInfo_freight.setCellData(j, "mblHblCls", scwin.hd_mblHblCls);
      ds_PartnerFreightInfo_freight.setCellData(j, "rsltsStdDt", dsHouse.getCellData(houseRow, "cjdt"));
      ds_PartnerFreightInfo_freight.setCellData(j, "drcrCls", "C");
      ds_PartnerFreightInfo_freight.modifyRowStatus(j, "C");
    }
    $c.gus.cfDisableBtnOnly($p, scwin._compact([grpBtn2]));
    $c.gus.cfDisableBtnOnly($p, scwin._compact([btn_AddRowPartner_freight]));
  } else if (idx === 2) {
    // Buying
    for (var k = 0; k < ds_BuyingFreightInfo_freight.getRowCount(); k++) {
      ds_BuyingFreightInfo_freight.setCellData(k, "odrNo", dsHouse.getCellData(houseRow, "odrNo"));
      ds_BuyingFreightInfo_freight.setCellData(k, "kcomcd", scwin.hd_kcomcd);
      ds_BuyingFreightInfo_freight.setCellData(k, "seaAirCls", scwin.hd_seaAirCls);
      ds_BuyingFreightInfo_freight.setCellData(k, "blNo", $c.str.trim($p, ed_blno.getValue()));
      ds_BuyingFreightInfo_freight.setCellData(k, "mhno", $c.str.trim($p, lc_hmhno.getValue()));
      ds_BuyingFreightInfo_freight.setCellData(k, "locPtnCls", "1");
      ds_BuyingFreightInfo_freight.setCellData(k, "mblHblCls", scwin.hd_mblHblCls);
      ds_BuyingFreightInfo_freight.setCellData(k, "rsltsStdDt", dsHouse.getCellData(houseRow, "cjdt"));
      ds_BuyingFreightInfo_freight.setCellData(k, "drcrCls", "C");
      ds_BuyingFreightInfo_freight.setCellData(k, "pchsTyp", "1");
      ds_BuyingFreightInfo_freight.modifyRowStatus(k, "C");
    }
    $c.gus.cfDisableBtnOnly($p, scwin._compact([grpBtn3]));
    $c.gus.cfDisableBtnOnly($p, scwin._compact([btn_Delete_freightRowBuying_freight]));
  }
};
