scwin._isFreightUnitCase = function (code) {
  if (!code) return false;
  var list = ["ADO", "ADOV", "APUV", "ALO", "AIT", "AHC", "AHCV", "APH", "CHC", "MHC", "ADL", "ADLC", "ADLV", "ADLZ", "AFD", "ASA", "CDLV", "INP", "ADL1", "DTY", "ACL", "ACLV", "AFC", "AOC", "AOCV", "BTC", "BTCV", "BTF", "BTFV", "AHCJ", "AOCJ", "AHCK", "AOCK"];
  return list.indexOf(code) >= 0;
};

