scwin.gr_SellingFreightInfo_freight_onviewchange = async function (info) {
  var colId = info.colId;
  var value = info.newValue;
  var rowIndex = info.rowIndex;
  switch (colId) {
    case "bilgClntNo":
      await scwin.f_PopUpGrid_freight("SellingCustomer", rowIndex, "T", "T", "F", "CODE");
      break;
    case "fareEngCd":
      await scwin.f_PopUpGrid_freight("SellingFreight", rowIndex, "T", "T", "F", "CODE");
      break;
    default:
      break;
  }
  scwin.f_PkgWegihtSetting_freight(rowIndex, colId, "Selling");
  switch (colId) {
    case "crcCd":
      await scwin.f_CurrRateSetting_freight(rowIndex, colId, "Selling");
      break;
    case "fareEngCd":
      if (scwin._isFreightUnitCase(value)) {
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "fareUnit", "P");
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "qty", 1);
      }
      if (value == "ATC" || value == "ATCV") {
        var houseRow = ds_HouseFreightInfo_freight.getRowPosition();
        if (houseRow < 0) houseRow = 0;
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "crcCd", "KRW");
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "exRate", 1);
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "sellUpr", 1);
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", ds_HouseFreightInfo_freight.getCellData(houseRow, "mftwht"));
        var chgWt = Number(ds_SellingFreightInfo_freight.getCellData(rowIndex, "grossWt") || 0);
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "sellAmt", Math.round(chgWt * 35 + 2000 - 0.5));
        if (curVal == "ATCV") {
          var sellAmt2 = Number(ds_SellingFreightInfo_freight.getCellData(rowIndex, "pchsAmt") || 0);
          ds_SellingFreightInfo_freight.setCellData(rowIndex, "vat", Math.round(sellAmt2 * 0.1 - 0.5));
        }
      }
      break;
    case "chgWt":
      scwin.f_GridChangeValidate_freight(ds_SellingFreightInfo_freight, rowIndex, colId);
      break;
    case "prtnAmt":
      break;
    case "fareUnit":
      if ("P" == ds_SellingFreightInfo_freight.getCellData(rowIndex, colId)) {
        //case
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "qty", 1);
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "chgWt", 0);
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", 0);
      } else if ("C" == ds_SellingFreightInfo_freight.getCellData(rowIndex, colId)) {
        //c/wt
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "qty", Number(ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition(), "tcwht")));
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "chgWt", Number(ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition(), "tcwht")));
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", 0);
      } else if ("G" == ds_SellingFreightInfo_freight.getCellData(rowIndex, colId)) {
        //g/wt
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", Number(ds_SellingFreightInfo_freight.getCellData(rowIndex, "qty")));
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "chgWt", 0);
      }
      break;
    case "qty":
      if ("P" == ds_SellingFreightInfo_freight.getCellData(rowIndex, "fareUnit")) {
        //case
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "chgWt", 0);
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", 0);
      } else if ("C" == ds_SellingFreightInfo_freight.getCellData(rowIndex, "fareUnit")) {
        //c/wt
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "qty", Number(ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition(), "tcwht")));
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "chgWt", Number(ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition(), "tcwht")));
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", 0);
      } else if ("G" == ds_SellingFreightInfo_freight.getCellData(rowIndex, "fareUnit")) {
        //g/wt
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "grossWt", Number(ds_SellingFreightInfo_freight.getCellData(rowIndex, "qty")));
        ds_SellingFreightInfo_freight.setCellData(rowIndex, "chgWt", 0);
      }
      break;
  }

  // row 금액 계산
  scwin.f_RateAmount_freight(rowIndex, colId, "Selling");

  // 합계
  scwin.f_TotalCac_freight("Selling");

  // Prepaid / Collect Summery
  scwin.f_pcSummery_freight();

  // 포커스 처리
  scwin.gridCellFocus.apply(gr_SellingFreightInfo_freight, []);
};

