/* =========================
 * 공통 엔진
 * ========================= */
scwin._dlGet = function (dl, r, colId) {
  if (!dl) return "";
  if (typeof dl.getCellData === "function") return dl.getCellData(r, colId);
  if (typeof dl.getValue === "function") return dl.getValue(r, colId);
  if (typeof dl.getCellValue === "function") return dl.getCellValue(r, colId);
  return "";
};
scwin._applyReadOnlyByConfig = function (grd, dl, mode, cfg) {
  if (!grd || !dl || !cfg) return;
  const gridEditable = mode === "Create" || mode === "Update";
  const rowCount = typeof dl.getRowCount === "function" ? dl.getRowCount() : 0;
  const colCount = cfg.colCount;
  const lockAll = (r, flag) => {
    for (let c = 0; c < colCount; c++) grd.setCellReadOnly(r, c, flag);
  };

  // Init/Retrieve: 전체 잠금
  if (!gridEditable) {
    for (let r = 0; r < rowCount; r++) lockAll(r, true);
    return;
  }
  for (let r = 0; r < rowCount; r++) {
    // 기본: 전부 잠금 후, 풀 것만 푼다(안전)
    lockAll(r, true);
    const invNo = (scwin._dlGet(dl, r, cfg.invColId) || "").trim();
    const hasInv = invNo !== "";
    const curr = cfg.currColId ? (scwin._dlGet(dl, r, cfg.currColId) || "").trim() : "";

    // (1) 항상 ReadOnly
    (cfg.alwaysReadOnlyCols || []).forEach(c => grd.setCellReadOnly(r, c, true));

    // (2) INV 없을 때만 editable
    (cfg.editableWhenNoInvCols || []).forEach(c => grd.setCellReadOnly(r, c, hasInv));

    // (3) 외화금액: INV 없고 && 통화 != KRW일 때만 editable
    if (cfg.fcrcColIndex != null) {
      const editableFcrc = !hasInv && curr !== "KRW";
      grd.setCellReadOnly(r, cfg.fcrcColIndex, !editableFcrc);
    }

    // (4) “항상 editable(편집모드에서)” 컬럼
    (cfg.alwaysEditableInEditModeCols || []).forEach(c => grd.setCellReadOnly(r, c, false));

    // (5) 추가 조건 컬럼(예: Partner vehclNo: drcrCls == "C" 일 때만)
    if (cfg.conditionalCols && cfg.conditionalCols.length) {
      cfg.conditionalCols.forEach(cond => {
        // cond: { colIndex, when: (r, dl) => boolean(editable?) }
        const editable = !!cond.when(r, dl);
        grd.setCellReadOnly(r, cond.colIndex, !editable);
      });
    }
  }
};

