scwin.f_GridSet_freight = function (gubun) {
  var isCheckEdit = false;
  switch (gubun) {
    case "Init":
      isCheckEdit = false;
    // break;
    case "Retrieve":
      isCheckEdit = false;
      break;
    case "Create":
      isCheckEdit = true;
      break;
    case "Update":
      isCheckEdit = true;
      break;
    default:
      break;
  }
  gr_SellingFreightInfo_freight.setColumnReadOnly("chk", !isCheckEdit);
  gr_PartnerFreightInfo_freight.setColumnReadOnly("chk", !isCheckEdit);
  gr_BuyingFreightInfo_freight.setColumnReadOnly("chk", !isCheckEdit);
};
